
// Code generated by Prompty emitter; DO NOT EDIT.

use agentschema::PromptyTool;


#[test]
fn test_prompty_tool_load_json() {
    let json = r####"
{
  "kind": "prompty",
  "path": "./summarize.prompty",
  "mode": "single"
}
"####;
    let result = PromptyTool::from_json(json);
    assert!(result.is_ok(), "Failed to load from JSON: {:?}", result.err());
    let instance = result.unwrap();
    assert_eq!(instance.kind, "prompty");
    assert_eq!(instance.path, "./summarize.prompty");
    assert_eq!(instance.mode, "single");
}

#[test]
fn test_prompty_tool_load_yaml() {
    let yaml = r####"
kind: prompty
path: ./summarize.prompty
mode: single

"####;
    let result = PromptyTool::from_yaml(yaml);
    assert!(result.is_ok(), "Failed to load from YAML: {:?}", result.err());
    let instance = result.unwrap();
    assert_eq!(instance.kind, "prompty");
    assert_eq!(instance.path, "./summarize.prompty");
    assert_eq!(instance.mode, "single");
}

#[test]
fn test_prompty_tool_roundtrip() {
    let json = r####"
{
  "kind": "prompty",
  "path": "./summarize.prompty",
  "mode": "single"
}
"####;
    let result = PromptyTool::from_json(json);
    assert!(result.is_ok(), "Failed to load: {:?}", result.err());
    let instance = result.unwrap();
    let json_output = instance.to_json();
    assert!(json_output.is_ok(), "Failed to serialize to JSON: {:?}", json_output.err());
}



